// Funci�n para preservar UTF-8 correctamente
function fixUtf8(str) {
  if (!str) return '';
  try {
    // Si ya es UTF-8 v�lido, devolverlo tal cual
    return decodeURIComponent(encodeURIComponent(str));
  } catch (e) {
    // Limpiar caracteres inv�lidos
    return str.replace(/[\uFFFD\uFFFE\uFFFF]/g, '').replace(/\x00/g, '');
  }
}

const body = $input.first().json.body || $input.first().json;
const companySlug = body.company_slug || 'default';
const assistantName = fixUtf8(body.assistant_name) || 'MIA';
const companyName = fixUtf8(body.company_name) || 'la empresa';
const userMessage = fixUtf8(body.user_message) || '';
const conversationHistory = body.conversation_history || body.context || [];
const openaiApiKey = body.openai_api_key || '';
const qdrantHost = body.qdrant_host || 'https://qdrant-production-f4e7.up.railway.app';
const timestamp = new Date().toISOString();
const deduplication = body.deduplication || null;
const collectionName = 'company_' + companySlug + '_knowledge';
const systemPrompt = 'Eres ' + assistantName + ', el asistente de entrenamiento de ' + companyName + '.\n\nTu rol es:\n1. Ayudar al usuario a entrenar y mejorar el bot de la empresa\n2. Entender ejemplos de conversaciones que te den\n3. Aprender correcciones sobre c�mo deber�as responder\n4. Registrar informaci�n importante sobre la empresa y sus clientes\n\nCuando el usuario te de un ejemplo o correcci�n:\n- Confirma que lo has entendido\n- Muestra c�mo responder�as en esa situaci�n\n- Pregunta si hay m�s ejemplos o informaci�n\n\nS� amigable, profesional y muestra que est�s aprendiendo.';

return {
  json: {
    company_slug: companySlug,
    assistant_name: assistantName,
    company_name: companyName,
    user_message: userMessage,
    conversation_history: conversationHistory,
    collection_name: collectionName,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    timestamp: timestamp,
    system_prompt: systemPrompt,
    deduplication: deduplication
  }
};

// Prepare Qdrant search request
const prevData = $('Prepare Training Data').first().json;
const embedding = $input.first().json.data[0].embedding;

return {
  json: {
    ...prevData,
    query_vector: embedding
  }
};

// Build context from Qdrant results and prepare OpenAI request
const prevData = $('Prepare Search').first().json;
const searchResults = $input.first().json.result || [];

let contextText = '';
if (searchResults && searchResults.length > 0) {
  contextText = searchResults
    .filter(r => r.score > 0.5)
    .map(r => r.payload?.text || '')
    .filter(t => t)
    .join('\n\n---\n\n');
}

if (!contextText) {
  contextText = 'Sin contexto previo en la base de conocimiento.';
}

const messages = [
  {
    role: 'system',
    content: prevData.system_prompt + '\n\nCONTEXTO DE LA EMPRESA (informaci?n ya aprendida):\n' + contextText
  }
];

if (prevData.conversation_history && prevData.conversation_history.length > 0) {
  for (const msg of prevData.conversation_history.slice(-10)) {
    messages.push({
      role: msg.role || 'user',
      content: msg.content || msg.message || ''
    });
  }
}

messages.push({
  role: 'user',
  content: prevData.user_message
});

return {
  json: {
    ...prevData,
    context_text: contextText,
    messages: messages
  }
};

const openaiResponse = $input.first().json;
const aiResponse = openaiResponse.choices[0].message.content || '';
const prevNode = $('Build Context & Messages');
const prevData = prevNode.first().json;
const userMessage = prevData.user_message || '';
const openaiApiKey = prevData.openai_api_key || '';
const collectionName = prevData.collection_name || '';
const companySlug = prevData.company_slug || '';
const qdrantHost = prevData.qdrant_host || '';
const deduplication = prevData.deduplication || null;

// 🔍 PRIMERO: Verificar si PHP ya detectó que es una pregunta (action === 'skip')
const isSkipped = deduplication && deduplication.action === 'skip';

// 🔍 SEGUNDO: Verificar si parece pregunta por patrones
const lowerMessage = userMessage.toLowerCase();
const questionIndicators = [
  '¿', '?',
  'qué ', 'que ', 'cuál ', 'cual ', 'cómo ', 'como ',
  'cuándo ', 'cuando ', 'dónde ', 'donde ', 'quién ', 'quien ',
  'tienen ', 'tienes ', 'hay ', 'existe ', 'puedo ', 'pueden '
];
const isQuestion = questionIndicators.some(q => lowerMessage.includes(q) || userMessage.includes(q));

// 🔍 TERCERO: Verificar si tiene keywords de entrenamiento
const saveKeywords = [
  'ejemplo', 'asi deberias', 'responde asi', 'cuando pregunten',
  'si alguien pregunta', 'recuerda que', 'importante',
  'nuestro horario', 'nuestros precios', 'vendemos', 'ofrecemos',
  'nuestro telefono', 'nuestra direccion', 'nuestro email',
  'nuestra pagina', 'nuestro whatsapp', 'abrimos', 'cerramos',
  'trabajamos de', 'atendemos de', 'el precio es', 'cuesta',
  'estamos ubicados', 'nuestra direccion es'
];
const hasTrainingKeywords = saveKeywords.some(kw => lowerMessage.includes(kw));

// 📝 DECISIÓN: Guardar solo si:
// - NO fue marcado como 'skip' por PHP
// - NO parece pregunta O tiene keywords de entrenamiento explícitos
const shouldSave = !isSkipped && (!isQuestion || hasTrainingKeywords);

const textToSave = userMessage; // Solo el mensaje, sin formato extra

return {
  json: {
    company_slug: companySlug,
    collection_name: collectionName,
    openai_api_key: openaiApiKey,
    qdrant_host: qdrantHost,
    deduplication: deduplication,
    user_message: userMessage,
    ai_response: aiResponse,
    should_save: shouldSave,
    is_question: isQuestion,
    is_skipped: isSkipped,
    text_to_save: textToSave
  }
};

// Get data from the node that passed through Should Save?
const prevData = $('Should Save?').first().json;
const embedding = $input.first().json.data[0].embedding;
const timestamp = new Date().toISOString();
const dedup = prevData.deduplication || {};
const action = dedup.action || 'create';
const pointId = dedup.point_id || Date.now();

// Extract only the useful knowledge from user message
// Remove training format, keep only the actual information
const userMsg = prevData.user_message || '';

// The text to save is just the user's information, clean and simple
const knowledgeText = userMsg.trim();

return {
  json: {
    collection_name: prevData.collection_name,
    qdrant_host: prevData.qdrant_host,
    action: action,
    point: {
      id: pointId,
      vector: embedding,
      payload: {
        text: knowledgeText,
        content: knowledgeText,
        type: 'training_message',
        category: 'entrenamiento',
        company_slug: prevData.company_slug,
        action: action,
        similarity: dedup.similarity || 0,
        last_updated: timestamp
      }
    }
  }
};

// Return response (saved path)
const processData = $('Process Response').first().json;
return {
  json: {
    response: processData.ai_response,
    saved: true,
    message: 'Guardado en la base de conocimiento'
  }
};

// Return response (not saved path)
const prevData = $('Process Response').first().json;
return {
  json: {
    response: prevData.response,
    saved: false
  }
};

